const week = 'Week of July 7–11, 2026';
const activity = {
  week,
  deployments: [
    { version: 'v2.4.1', date: 'July 12', type: 'patch', summary: 'Fixed dashboard timeout for workspaces with 200+ projects. Resolved mobile Safari assignee dropdown reset. Emergency patch triggered by BUG-2041.' },
    { version: 'v2.4.0', date: 'July 8', type: 'minor', summary: 'Shipped custom fields v2 (text, number, date types). Refactored CSV export pipeline. Added project template library.' }
  ],
  incidents: [
    { id: 'INC-089', severity: 'P0', title: 'Dashboard 504 timeout — 12 enterprise accounts', duration_minutes: 47, resolved: true, root_cause: 'Missing query limit in dashboard projects endpoint introduced in v2.4.1' }
  ],
  prs_merged: [
    { id: 'PR-1847', title: 'Migrate auth middleware to async bcrypt', author: 'Backend team', area: 'backend/auth' },
    { id: 'PR-1851', title: 'Add memoisation to TaskList component', author: 'Frontend team', area: 'frontend/performance' },
    { id: 'PR-1855', title: 'Add task dependency graph endpoint', author: 'Backend team', area: 'backend/api' }
  ],
  upcoming_this_week: 'v2.5.0 planned — includes recurring tasks discoverability redesign (3 FE engineers, estimate 5 days)'
};
return [{ json: { activity } }];

const { activity: a } = $input.first().json;
const depText = a.deployments.map(d => `  ${d.version} (${d.type}, ${d.date}): ${d.summary}`).join('
');
const incText = a.incidents.map(i => `  [${i.severity}] ${i.title} — ${i.duration_minutes}min, ${i.resolved?'RESOLVED':'ONGOING'}. Root cause: ${i.root_cause}`).join('
');
const prText = a.prs_merged.map(p => `  ${p.id}: ${p.title} (${p.area})`).join('
');
const system = `You are an engineering lead writing a weekly digest for a non-technical PM. You translate engineering activity into clear business language: what shipped, what broke and is fixed, what engineering is doing that matters for the roadmap. You are concise, avoid jargon, and always connect engineering work to product and customer outcomes. Return ONLY valid JSON.`;
const user = `Write a PM-readable engineering digest for: ${a.week}

Deployments:
${depText}

Incidents:
${incText}

PRs merged:
${prText}

Upcoming:
${a.upcoming_this_week}

Return JSON:
{
  "digest_title": "string",
  "tldr": "string — 2 sentences max: what PMs most need to know this week",
  "what_shipped": [{ "item": "string", "customer_impact": "string" }],
  "what_broke_and_is_fixed": [{ "incident": "string", "customer_impact": "string", "status": "resolved|ongoing" }],
  "what_engineering_is_doing": [{ "work": "string", "why_it_matters": "string" }],
  "next_week_preview": "string",
  "action_required_from_pm": "string|null"
}`;
return [{ json: { activity: a, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Digest Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.tldr) return [{ json: { _error: true, reason: 'Missing tldr field' } }];
return [{ json: { _error: false, digest: parsed, meta: { week: upstream.activity.week, generated_at: new Date().toISOString() } } }];
